import{_ as a,a as d,b as e,c as n}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as s,o,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"WebDAV 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/webdav.md","filePath":"ko-KR/upload/webdav.md","lastUpdated":1781962217000}'),i={name:"ko-KR/upload/webdav.md"};function p(c,t,h,b,m,u){return o(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="webdav-채널-추가" tabindex="-1">WebDAV 채널 추가 <a class="header-anchor" href="#webdav-채널-추가" aria-label="Permalink to &quot;WebDAV 채널 추가&quot;">​</a></h1><p>WebDAV 채널은 NAS, 클라우드 드라이브, WebDAV 지원 저장소에 파일을 저장하기 위한 설정입니다.</p><h2 id="적합한-경우" tabindex="-1">적합한 경우 <a class="header-anchor" href="#적합한-경우" aria-label="Permalink to &quot;적합한 경우&quot;">​</a></h2><ul><li>NAS나 온라인 스토리지가 WebDAV 주소를 제공합니다.</li><li>업로드한 이미지를 내 WebDAV 디렉터리에 저장하고 싶습니다.</li><li>설정과 인증 정보를 D1의 <code>upload_channels</code>에 저장하고, 프론트엔드에 오래 노출하고 싶지 않습니다.</li></ul><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>예: <code>https://nas.example.com/dav</code></td></tr><tr><td>사용자 이름</td><td>WebDAV 로그인</td></tr><tr><td>비밀번호</td><td>WebDAV 로그인. 가능하면 앱 비밀번호 사용</td></tr><tr><td>인증 방식</td><td>보통 <code>Basic</code>, 필요 시 <code>Digest</code></td></tr><tr><td>저장 디렉터리</td><td>선택 사항. 기본값은 <code>imgbed</code></td></tr></tbody></table><h2 id="앱-비밀번호-사용" tabindex="-1">앱 비밀번호 사용 <a class="header-anchor" href="#앱-비밀번호-사용" aria-label="Permalink to &quot;앱 비밀번호 사용&quot;">​</a></h2><p>서비스가 앱 비밀번호를 지원한다면 일반 계정 비밀번호 대신 앱 비밀번호를 쓰는 것이 좋습니다.</p><p><img src="'+a+'" alt="앱 비밀번호 만들기" loading="lazy"></p><p>생성 후 표시되는 비밀번호는 한 번만 보일 수 있습니다.</p><p><img src="'+d+'" alt="앱 비밀번호 저장" loading="lazy"></p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>WebDAV</code>를 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>NAS</code>, <code>Koofr</code></td></tr><tr><td>Endpoint</td><td><code>https://</code>를 포함한 WebDAV URL</td></tr><tr><td>사용자 이름</td><td>WebDAV 계정</td></tr><tr><td>비밀번호</td><td>비밀번호 또는 앱 비밀번호</td></tr><tr><td>인증 방식</td><td>먼저 <code>Basic</code>으로 시도</td></tr><tr><td>저장 디렉터리</td><td>선택 사항. 보통 <code>imgbed</code></td></tr></tbody></table><p><img src="'+e+'" alt="WebDAV 설정" loading="lazy"></p><h2 id="큰-파일-처리-방식" tabindex="-1">큰 파일 처리 방식 <a class="header-anchor" href="#큰-파일-처리-방식" aria-label="Permalink to &quot;큰 파일 처리 방식&quot;">​</a></h2><p>WebDAV 채널은 큰 파일을 세션 기반 분할 업로드로 처리합니다.</p><table tabindex="0"><thead><tr><th>파일 크기</th><th>업로드 방식</th><th>원격 저장 형태</th></tr></thead><tbody><tr><td>64 MiB 이하</td><td>일반 업로드</td><td>하나의 완전한 파일</td></tr><tr><td>64 MiB 초과</td><td>분할 업로드</td><td>분할 디렉터리 안의 여러 chunk</td></tr></tbody></table><p>WebDAV 서버가 <code>partial update</code>나 오프셋 쓰기를 지원할 필요는 없습니다. ImgBed는 분할 목록을 기록하고, 읽을 때 순서대로 합쳐 반환합니다.</p><p>파일 URL은 바뀌지 않으며 사용자는 기존 <code>/file/...</code> 링크로 접근합니다.</p><h2 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h2><table tabindex="0"><thead><tr><th>확인 항목</th><th>정상 상태</th></tr></thead><tbody><tr><td>채널 카드</td><td>저장 후 표시됨</td></tr><tr><td>작은 파일</td><td>WebDAV 디렉터리에 파일 생성</td></tr><tr><td>큰 파일</td><td>분할 디렉터리와 chunk 생성</td></tr><tr><td>용량 조회</td><td>서버가 지원하면 사용량 표시</td></tr></tbody></table><p><img src="'+n+`" alt="용량 조회" loading="lazy"></p><p>용량 조회가 실패하더라도 작은 파일 업로드가 정상이라면, 서버가 용량 정보를 제공하지 않는 것일 수 있습니다.</p><h2 id="빠른-절차" tabindex="-1">빠른 절차 <a class="header-anchor" href="#빠른-절차" aria-label="Permalink to &quot;빠른 절차&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV Endpoint, 사용자 이름, 비밀번호 준비</span></span>
<span class="line"><span>-&gt; 업로드 설정 열기</span></span>
<span class="line"><span>-&gt; 채널 추가</span></span>
<span class="line"><span>-&gt; WebDAV 선택</span></span>
<span class="line"><span>-&gt; Endpoint / 사용자 이름 / 비밀번호 입력</span></span>
<span class="line"><span>-&gt; 인증 방식은 먼저 Basic</span></span>
<span class="line"><span>-&gt; 저장</span></span>
<span class="line"><span>-&gt; 용량 조회</span></span>
<span class="line"><span>-&gt; 테스트 파일 업로드</span></span></code></pre></div>`,26)])])}const D=s(i,[["render",p]]);export{A as __pageData,D as default};
